int price = 80;
int quantity = 2;
int customerPoints = 9;
bool isMember = true;

int total = price * quantity;

if (isMember && total >= 100)
{
    total -= 20;
    customerPoints++;
    Console.WriteLine("Member discount applied");
}
else if (total >= 100)
{
    total -= 10;
    Console.WriteLine("Regular discount applied");
}
else
{
    total += 5;
    customerPoints--;
    Console.WriteLine("Small order fee added");
}

if (customerPoints >= 10 || isMember)
{
    Console.WriteLine("Bonus available");
}
else
{
    Console.WriteLine("No bonus yet");
}

Console.WriteLine(total);
Console.WriteLine(customerPoints);

