int ticketPrice = 30;
int tickets = 4;
int bonusPoints = 8;
bool hasDiscountCard = true;

int total = ticketPrice * tickets;

if (hasDiscountCard && total >= 100)
{
    total -= 15;
    bonusPoints++;
    Console.WriteLine("Card discount applied");
}
else if (total >= 100)
{
    total -= 5;
    Console.WriteLine("Small discount applied");
}
else
{
    total += 3;
    bonusPoints--;
    Console.WriteLine("Service fee added");
}

if (bonusPoints >= 9 || hasDiscountCard)
{
    Console.WriteLine("Extra bonus available");
}
else
{
    Console.WriteLine("No extra bonus");
}

Console.WriteLine(total);
Console.WriteLine(bonusPoints);
